import{_ as e,o as s,c as i,a2 as t}from"./chunks/framework.BKG_UbFK.js";const u=JSON.parse('{"title":"Instalación","description":"","frontmatter":{},"headers":[],"relativePath":"es/guide/installation.md","filePath":"es/guide/installation.md"}'),l={name:"es/guide/installation.md"};function o(n,a,c,r,d,p){return s(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="instalacion" tabindex="-1">Instalación <a class="header-anchor" href="#instalacion" aria-label="Permalink to &quot;Instalación&quot;">​</a></h1><h2 id="requisitos" tabindex="-1">Requisitos <a class="header-anchor" href="#requisitos" aria-label="Permalink to &quot;Requisitos&quot;">​</a></h2><p>Consulta la <a href="/clearance-docs/es/guide/introduction.html#requirements">tabla de requisitos</a> completa en la página de Introducción - PHP ^8.3, Laravel ^11.0|^12.0|^13.0, spatie/laravel-permission ^6.0, livewire/livewire ^3.0|^4.0, livewire/flux ^2.14.</p><h2 id="instalar-el-paquete" tabindex="-1">Instalar el paquete <a class="header-anchor" href="#instalar-el-paquete" aria-label="Permalink to &quot;Instalar el paquete&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">composer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> require</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rivalex/clearance</span></span></code></pre></div><h2 id="ejecutar-el-instalador" tabindex="-1">Ejecutar el instalador <a class="header-anchor" href="#ejecutar-el-instalador" aria-label="Permalink to &quot;Ejecutar el instalador&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:install</span></span></code></pre></div><div class="danger custom-block"><p class="custom-block-title">Ejecuta siempre clearance:install, nunca un migrate simple</p><p>Las propias migraciones de Clearance dependen de que existan primero las tablas <code>roles</code>/<code>permissions</code> de Spatie; el instalador publica y ejecuta las migraciones de Spatie antes que las suyas. Si ejecutas <code>php artisan migrate</code> directamente en una instalación nueva y Spatie aún no está configurado, obtendrás un mensaje de error accionable indicándote que ejecutes el instalador en su lugar.</p></div><h3 id="flags-opcionales" tabindex="-1">Flags opcionales <a class="header-anchor" href="#flags-opcionales" aria-label="Permalink to &quot;Flags opcionales&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Flag</th><th>Descripción</th></tr></thead><tbody><tr><td><code>--user=ID</code></td><td>Asigna el rol <code>super_admin</code> a un usuario tras la instalación</td></tr><tr><td><code>--role=NAME</code></td><td>Asigna <code>clearance-access</code> a un rol (se crea si no existe)</td></tr><tr><td><code>--super-admin-role=NAME</code></td><td>Promueve un rol existente a <code>super_admin</code> (omite el prompt interactivo)</td></tr><tr><td><code>--force</code></td><td>Vuelve a ejecutar aunque ya esté instalado</td></tr></tbody></table><h3 id="que-hace-el-instalador" tabindex="-1">Qué hace el instalador <a class="header-anchor" href="#que-hace-el-instalador" aria-label="Permalink to &quot;Qué hace el instalador&quot;">​</a></h3><ol><li>Publica <code>config/clearance.php</code>.</li><li>Publica las migraciones de Clearance.</li><li>Detecta las tablas de Spatie Permission - si la tabla <code>roles</code> no existe, publica y ejecuta primero las migraciones de Spatie automáticamente.</li><li>Ejecuta todas las migraciones pendientes.</li><li>Crea <code>clearance-access</code> y los 5 permisos de capacidad granulares: <code>clearance-permissions-write</code>, <code>clearance-roles-write</code>, <code>clearance-guards-write</code>, <code>clearance-settings-write</code>, <code>clearance-users-write</code>.</li><li>Crea el rol <code>super_admin</code> con todos los permisos <code>clearance-*</code> asignados (aditivo - nunca elimina permisos existentes al volver a ejecutarse).</li><li>Escribe <code>storage/.clearance-installed</code> como marcador de idempotencia.</li></ol><div class="tip custom-block"><p class="custom-block-title">¿Migrando desde una instalación de Spatie existente?</p><p>Usa <code>php artisan clearance:backfill</code> en lugar de empezar desde cero, y lee primero la <a href="/clearance-docs/es/guide/migration.html">guía de Migración</a> - cubre la colisión con <code>super_admin</code>, subclases de modelo personalizadas, e importación de guards.</p></div><h2 id="anade-hasclearance-a-tu-modelo-user" tabindex="-1">Añade HasClearance a tu modelo User <a class="header-anchor" href="#anade-hasclearance-a-tu-modelo-user" aria-label="Permalink to &quot;Añade HasClearance a tu modelo User&quot;">​</a></h2><p>Para usar los métodos de autorización contextual (<code>$user-&gt;canIn()</code>, <code>$user-&gt;hasRoleIn()</code>), añade el trait <code>HasClearance</code> a <code>App\\Models\\User</code>. Ya incluye el <code>HasRoles</code> de Spatie - una sola línea reemplaza a ambos:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">use</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Rivalex\\Clearance\\Traits\\HasClearance</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> User</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> extends</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Authenticatable</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    use</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> HasClearance</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// includes HasRoles + all contextual authorization methods</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">¿Ya usas <code>use HasRoles</code>?</p><p>Reemplázalo con <code>use HasClearance</code>, o conserva ambos - PHP deduplica automáticamente la composición de traits, sin conflictos.</p></div><p>Sin este trait, <code>$user-&gt;canIn()</code> y los métodos relacionados no están disponibles, pero las directivas Blade (<code>@canin</code>, <code>@hasrolein</code>) y <code>ContextService</code> siguen funcionando de todos modos - no dependen del trait. Consulta <a href="/clearance-docs/es/features/contextual-authorization.html">Autorización Contextual</a> para más detalles.</p><h2 id="proximos-pasos" tabindex="-1">Próximos pasos <a class="header-anchor" href="#proximos-pasos" aria-label="Permalink to &quot;Próximos pasos&quot;">​</a></h2><p>Continúa con el <a href="/clearance-docs/es/guide/quick-start.html">Inicio Rápido</a> para montar el panel y empezar a gestionar permisos.</p>`,20)])])}const m=e(l,[["render",o]]);export{u as __pageData,m as default};
